css:
.print-format {
    font-family: Arial, Helvetica, sans-serif;
    font-size: 10pt;
    line-height: 1.45;
    color: #222;
}

.nfa-document {
    width: 100%;
}

.print-heading {
    margin-bottom: 26px;
    text-align: center;
}

.print-heading h2 {
    margin: 0;
    font-size: 18pt;
    font-weight: 700;
    line-height: 1.2;
    text-transform: uppercase;
}

.print-heading .outcome-label {
    margin-top: 7px;
    font-size: 12pt;
    font-weight: 600;
}

.print-heading .document-name {
    margin-top: 6px;
    font-size: 9pt;
    color: #666;
}

.nfa-section-heading {
    margin: 22px 0 10px;
    padding-bottom: 5px;
    border-bottom: 1px solid #b40000;
    font-size: 12pt;
    font-weight: 700;
    page-break-after: avoid;
}

.nfa-table {
    width: 100%;
    margin: 0 0 18px;
    border: 1px solid #d7d7d7;
    border-collapse: collapse;
    page-break-inside: avoid;
}

.nfa-table th,
.nfa-table td {
    padding: 8px 9px;
    border: 1px solid #d7d7d7;
    vertical-align: top;
    text-align: left;
}

.nfa-table th {
    background: #f3f3f3;
    font-weight: 700;
}

.nfa-table thead {
    display: table-header-group;
}

.nfa-table tbody tr {
    page-break-inside: avoid;
}

.nfa-details-table th {
    width: 20%;
}

.nfa-details-table td {
    width: 30%;
}

.nfa-outcome-box {
    margin: 18px 0 22px;
    padding: 13px;
    border: 2px solid #333;
    text-align: center;
    page-break-inside: avoid;
}

.nfa-outcome-box__label {
    margin-bottom: 4px;
    font-size: 9pt;
    color: #666;
    text-transform: uppercase;
}

.nfa-outcome-box__value {
    font-size: 15pt;
    font-weight: 700;
}

.nfa-summary {
    margin: 12px 0 20px;
    padding: 12px 14px;
    border: 1px solid #d7d7d7;
    border-left: 4px solid #b40000;
    background: #fafafa;
    page-break-inside: avoid;
}

.nfa-summary p {
    margin: 0 0 8px;
}

.nfa-summary p:last-child {
    margin-bottom: 0;
}

.nfa-secondary-value {
    margin-top: 3px;
    font-size: 9pt;
    color: #666;
}

.preserve-lines {
    white-space: pre-line;
}

.no-data {
    margin: 8px 0 18px;
    color: #777;
    font-style: italic;
}

.signatures {
    margin-top: 34px;
    page-break-inside: avoid;
}

.signatures table {
    width: 100%;
    border-collapse: collapse;
}

.signatures td {
    width: 50%;
    padding: 18px 24px 14px 0;
    border: none;
    vertical-align: bottom;
}

.signatures td:nth-child(even) {
    padding-right: 0;
}

.signature-space {
    height: 34px;
}

.signature-line {
    width: 100%;
    margin-bottom: 5px;
    border-top: 1px solid #333;
}

.signatures p {
    margin: 0;
    font-size: 9pt;
}

@media print {
    .nfa-table,
    .nfa-summary,
    .nfa-outcome-box,
    .signatures {
        page-break-inside: avoid;
    }

    .nfa-section-heading {
        page-break-after: avoid;
    }
}

@page {
    size: A4;
    margin: 15mm;
}
